class Solution {
    public String robotWithString(String s) {
        StringBuilder p = new StringBuilder();
        while (!s.isEmpty() || !p.toString().isEmpty()) {
            if (!s.isEmpty() && (p.toString().isEmpty() || s.charAt(0) < p.charAt(p.length() - 1))) {
